// TG-72: Fetch all snapshots from last 30 days for trend analysis
const competitors = Array.isArray($input.first().json) ? $input.first().json : [];
if (competitors.length === 0) {
  return [{ json: { competitors: [], snapshots: [], error: 'No active competitors' } }];
}

const supabaseUrl = $vars.TG_SUPABASE_URL + '/rest/v1';
const supabaseKey = $vars.TG_SUPABASE_SERVICE_KEY;
const supabaseHeaders = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];

// Fetch all snapshots for all competitors in one query
const competitorIds = competitors.map(c => c.id);
let allSnapshots = [];
try {
  allSnapshots = await this.helpers.httpRequest({
    method: 'GET',
    url: `${supabaseUrl}/competitor_snapshots?snapshot_date=gte.${thirtyDaysAgo}&order=snapshot_date.desc`,
    headers: supabaseHeaders
  });
} catch (e) { /* no snapshots */ }

// Group snapshots by competitor_id
const byCompetitor = {};
for (const snap of (allSnapshots || [])) {
  if (!byCompetitor[snap.competitor_id]) byCompetitor[snap.competitor_id] = [];
  byCompetitor[snap.competitor_id].push(snap);
}

// Build enriched competitor data
const enriched = competitors.map(c => {
  const snaps = byCompetitor[c.id] || [];
  const latestSnap = snaps[0] || null;
  const oldestSnap = snaps[snaps.length - 1] || null;

  // Parse notable_changes from latest snapshot
  let latestChanges = null;
  if (latestSnap && latestSnap.notable_changes) {
    try {
      latestChanges = typeof latestSnap.notable_changes === 'string'
        ? JSON.parse(latestSnap.notable_changes)
        : latestSnap.notable_changes;
    } catch (e) { /* not JSON */ }
  }

  return {
    name: c.name,
    domain: c.domain,
    services: c.services,
    location: c.location,
    priority: c.priority,
    snapshot_count: snaps.length,
    latest_rating: latestSnap ? latestSnap.rating : null,
    latest_review_count: latestSnap ? latestSnap.review_count : null,
    oldest_rating: oldestSnap ? oldestSnap.rating : null,
    oldest_review_count: oldestSnap ? oldestSnap.review_count : null,
    review_growth: (latestSnap && oldestSnap) ? (latestSnap.review_count || 0) - (oldestSnap.review_count || 0) : 0,
    rating_change: (latestSnap && oldestSnap) ? Math.round(((latestSnap.rating || 0) - (oldestSnap.rating || 0)) * 100) / 100 : 0,
    website_title: latestChanges ? latestChanges.website_title : null,
    website_status: latestChanges ? latestChanges.website_status : null
  };
});

const month = new Date().toLocaleString('default', { month: 'long', year: 'numeric' });
return [{ json: { competitors: enriched, month, total_snapshots: allSnapshots.length } }];

// TG-72: Build monthly intelligence report
const { competitors, month, total_snapshots } = $input.first().json;

const lines = [
  `MONTHLY COMPETITOR INTELLIGENCE`,
  `${month}`,
  `Data points: ${total_snapshots} snapshots across ${competitors.length} competitors`,
  ''
];

// Sort by priority
const sorted = [...competitors].sort((a, b) => (a.priority || 99) - (b.priority || 99));

for (const c of sorted) {
  const statusIcon = c.website_status === 'up' ? '\u2705' : (c.website_status ? '\u274c' : '\u2753');
  lines.push(`${statusIcon} ${c.name}`);
  lines.push(`   Domain: ${c.domain || 'unknown'}`);
  lines.push(`   Services: ${(c.services || []).join(', ') || 'unknown'}`);
  lines.push(`   Location: ${c.location || 'unknown'}`);

  if (c.latest_rating !== null) {
    lines.push(`   Rating: ${c.latest_rating} (change: ${c.rating_change >= 0 ? '+' : ''}${c.rating_change})`);
  }
  if (c.latest_review_count !== null) {
    lines.push(`   Reviews: ${c.latest_review_count} (growth: +${c.review_growth})`);
  }
  if (c.website_title) {
    lines.push(`   Title: ${c.website_title.substring(0, 60)}`);
  }
  lines.push('');
}

// Summary insights
lines.push('--- INSIGHTS ---');
const fastGrowers = sorted.filter(c => c.review_growth > 3);
if (fastGrowers.length > 0) {
  lines.push(`Fast review growers: ${fastGrowers.map(c => `${c.name} (+${c.review_growth})`).join(', ')}`);
}
const downSites = sorted.filter(c => c.website_status === 'down_or_error');
if (downSites.length > 0) {
  lines.push(`Websites down: ${downSites.map(c => c.name).join(', ')}`);
}
if (fastGrowers.length === 0 && downSites.length === 0) {
  lines.push('No significant changes detected this month.');
}

return [{ json: { report: lines.join('\n'), month, competitor_count: competitors.length } }];
